// Establish domain and page_closure equalities between post1, post2, and pre_self_.
// Both posts share these with pre_self_ by the ensures clauses.
assert(post1_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post2_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post1_self_.thread_dom() =~= pre_self_.thread_dom());
assert(post2_self_.thread_dom() =~= pre_self_.thread_dom());
assert(post1_self_.container_dom() =~= pre_self_.container_dom());
assert(post2_self_.container_dom() =~= pre_self_.container_dom());
assert(post1_self_.endpoint_dom() =~= pre_self_.endpoint_dom());
assert(post2_self_.endpoint_dom() =~= pre_self_.endpoint_dom());
assert(post1_self_.page_closure() =~= pre_self_.page_closure());
assert(post2_self_.page_closure() =~= pre_self_.page_closure());

// Transitively, post1 and post2 agree on doms and page_closure.
assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());
assert(post1_self_.thread_dom() =~= post2_self_.thread_dom());
assert(post1_self_.container_dom() =~= post2_self_.container_dom());
assert(post1_self_.endpoint_dom() =~= post2_self_.endpoint_dom());
assert(post1_self_.page_closure() =~= post2_self_.page_closure());

// Per-element equalities. Each by-body materialises the intermediate
// equalities through pre_self_ so that whichever trigger Verus picked for
// the original ensures-forall (auto-chosen) actually fires on the bound
// variable: we mention both post*.get_*(x) and pre_self_.get_*(x) in the
// proof context, which covers every plausible auto-trigger choice.

assert forall|p_ptr: ProcPtr|
    post1_self_.proc_dom().contains(p_ptr) implies
    post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr) by {
    assert(post2_self_.proc_dom().contains(p_ptr));
    assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
};

assert forall|t_ptr: ThreadPtr|
    post1_self_.thread_dom().contains(t_ptr) implies
    post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr) by {
    assert(post2_self_.thread_dom().contains(t_ptr));
    assert(post1_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr));
    assert(post2_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr));
};

assert forall|e_ptr: EndpointPtr|
    post1_self_.endpoint_dom().contains(e_ptr) implies
    post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr) by {
    assert(post2_self_.endpoint_dom().contains(e_ptr));
    assert(post1_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));
    assert(post2_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));
};

// Container forall mirrors the ensures: only for c_ptr != container_ptr.
// We do NOT attempt to prove full Container equality at c_ptr == container_ptr
// because the `can_have_children` field is not pinned by the ensures.
assert forall|c_ptr: ContainerPtr|
    post1_self_.container_dom().contains(c_ptr) && c_ptr != container_ptr implies
    post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr) by {
    assert(post2_self_.container_dom().contains(c_ptr));
    assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
    assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
};

// Per-field equalities at the modified container_ptr (these are exactly the
// fields enumerated in the ensures; det_*_equal mirrors the ensures shape).
assert(post1_self_.get_container(container_ptr).owned_procs
    =~= post2_self_.get_container(container_ptr).owned_procs);
assert(post1_self_.get_container(container_ptr).parent
    =~= post2_self_.get_container(container_ptr).parent);
assert(post1_self_.get_container(container_ptr).parent_rev_ptr
    =~= post2_self_.get_container(container_ptr).parent_rev_ptr);
assert(post1_self_.get_container(container_ptr).children
    =~= post2_self_.get_container(container_ptr).children);
assert(post1_self_.get_container(container_ptr).owned_endpoints
    =~= post2_self_.get_container(container_ptr).owned_endpoints);
assert(post1_self_.get_container(container_ptr).owned_threads
    =~= post2_self_.get_container(container_ptr).owned_threads);
assert(post1_self_.get_container(container_ptr).owned_cpus
    =~= post2_self_.get_container(container_ptr).owned_cpus);
assert(post1_self_.get_container(container_ptr).scheduler
    =~= post2_self_.get_container(container_ptr).scheduler);
assert(post1_self_.get_container(container_ptr).depth
    =~= post2_self_.get_container(container_ptr).depth);
assert(post1_self_.get_container(container_ptr).uppertree_seq
    =~= post2_self_.get_container(container_ptr).uppertree_seq);
assert(post1_self_.get_container(container_ptr).subtree_set
    =~= post2_self_.get_container(container_ptr).subtree_set);
assert(post1_self_.get_container(container_ptr).root_process
    =~= post2_self_.get_container(container_ptr).root_process);
assert(post1_self_.get_container(container_ptr).quota
    =~= pre_self_.get_container(container_ptr).quota.spec_set_mem_4k(new_quota));
assert(post2_self_.get_container(container_ptr).quota
    =~= pre_self_.get_container(container_ptr).quota.spec_set_mem_4k(new_quota));
assert(post1_self_.get_container(container_ptr).quota
    =~= post2_self_.get_container(container_ptr).quota);
